import { publish, subscribe } from "../lib/sse";

// ---------------------------------------------------------------------------
// In-memory spec job registry
// ---------------------------------------------------------------------------
// Each background spec run is tracked here from the moment the POST fires
// until it completes (or the server restarts). The Map is keyed by a short
// random job ID that lives in the redirect URL.
//
// Eviction: jobs are kept for 10 minutes after completion so late-arriving
// SSE clients still get a "done" snapshot. The autopilot-ish ticker below
// sweeps stale entries.

export type SpecStage =
  | "queued"
  | "analyzing"
  | "writing"
  | "opening_pr"
  | "done"
  | "error";

export interface SpecJob {
  id: string;
  owner: string;
  repo: string;
  stage: SpecStage;
  label: string; // human-readable stage label
  prNumber: number | null;
  error: string | null;
  startedAt: number; // Date.now()
  completedAt: number | null;
}

const specJobs = new Map<string, SpecJob>();

// Sweep completed jobs older than 10 minutes.
setInterval(() => {
  const cutoff = Date.now() - 10 * 60 * 1000;
  for (const [id, job] of specJobs) {
    if (job.completedAt !== null && job.completedAt < cutoff) {
      specJobs.delete(id);
    }
  }
}, 60_000);

function specJobTopic(jobId: string): string {
  return `spec-job:${jobId}`;
}

/** Advance a job to a new stage and publish the SSE event. */
function advanceStage(job: SpecJob, stage: SpecStage, label: string): void {
  job.stage = stage;
  job.label = label;
  publish(specJobTopic(job.id), {
    event: "stage",
    data: { stage, label, prNumber: job.prNumber, error: job.error },
  });
}

const STAGE_LABELS: Record<SpecStage, string> = {
  queued: "Queued",
  analyzing: "Analyzing spec",
  writing: "Writing code",
  opening_pr: "Opening PR",
  done: "Done",
  error: "Error",
};

/**
 * Run the spec-to-PR pipeline in the background, publishing SSE events at
 * each stage transition. Accepts the same arguments as `createSpecPR`.
 */
async function runSpecJobInBackground(
  job: SpecJob,
  args: { repoId: string; spec: string; baseRef: string; userId: string }
): Promise<void> {
  // Stage 1 — analyzing spec / building context
  advanceStage(job, "analyzing", STAGE_LABELS.analyzing);

  // Dynamically import the backend (same guard as the POST handler).
  let createSpecPR:
    | ((args: {
        repoId: string;
        spec: string;
        baseRef: string;
        userId: string;
      }) => Promise<
        | { ok: true; prNumber: number }
        | { ok: false; error: string }
      >)
    | null = null;
  try {
    const mod: any = await import("../lib/spec-to-pr");
    createSpecPR =
      (mod && (mod.createSpecPR || (mod.default && mod.default.createSpecPR))) ||
      null;
  } catch {
    createSpecPR = null;
  }

  if (!createSpecPR) {
    job.error = "Backend not available — spec-to-PR is not deployed yet.";
    job.completedAt = Date.now();
    advanceStage(job, "error", STAGE_LABELS.error);
    return;
  }

  // Stage 2 — writing code (AI generating). We publish this immediately
  // before the Claude call so the UI shows "Writing code" while we wait.
  advanceStage(job, "writing", STAGE_LABELS.writing);

  let result: { ok: true; prNumber: number } | { ok: false; error: string };
  try {
    result = await createSpecPR(args);
  } catch (err) {
    result = {
      ok: false,
      error: err instanceof Error ? err.message : "Unexpected error",
    };
  }

  if (!result.ok) {
    job.error = result.error;
    job.completedAt = Date.now();
    advanceStage(job, "error", STAGE_LABELS.error);
    return;
  }

  // Stage 3 — opening PR (the insert already happened inside createSpecPR,
  // but we surface this stage as a brief acknowledgement).
  advanceStage(job, "opening_pr", STAGE_LABELS.opening_pr);
  job.prNumber = result.prNumber;

  // Stage 4 — done.
  job.completedAt = Date.now();
  advanceStage(job, "done", STAGE_LABELS.done);
}

const specs = new Hono<AuthEnv>();

// Tiny inline script that disables the submit button + textarea while the
// request is in-flight so users don't accidentally double-click and trigger
// two 10-30s Claude calls. Rendered as a plain <script> tag.
const DISABLE_ON_SUBMIT_JS = `
(function() {
  var form = document.getElementById('spec-form');
  if (!form) return;
  form.addEventListener('submit', function() {
    var btn = form.querySelector('button[type="submit"]');
    var ta = form.querySelector('textarea[name="spec"]');
    if (btn) {
      btn.disabled = true;
      btn.textContent = 'Working… this can take 10-30s';
    }
    if (ta) ta.readOnly = true;
  });
})();
`;

