/** Inline JS for the progress page — polls /status every 2s. ~18 lines. */
const PROGRESS_POLL_JS = `
(function() {
  var stages = ['queued','analyzing','writing','opening_pr','done','error'];
  var url = location.pathname.replace(/\\/progress$/, '/status');
  function update(d) {
    stages.forEach(function(s) {
      var dot = document.getElementById('dot-' + s);
      var lbl = document.getElementById('lbl-' + s);
      if (!dot || !lbl) return;
      dot.className = 'sp-dot';
      lbl.className = 'sp-step-label';
      var si = stages.indexOf(s), di = stages.indexOf(d.stage);
      if (si < di) { dot.className += ' is-done'; lbl.className += ' is-done'; }
      else if (s === d.stage && s !== 'error') { dot.className += ' is-active'; lbl.className += ' is-active'; }
      else if (s === 'error' && d.stage === 'error') { dot.className += ' is-error'; lbl.className += ' is-error'; }
    });
    if (d.stage === 'done' && d.prNumber) {
      var c = document.getElementById('sp-done-card');
      var lk = document.getElementById('sp-pr-link');
      if (c) c.className = 'sp-done-card is-visible';
      if (lk) lk.href = lk.dataset.base + '/' + d.prNumber;
    }
    if (d.stage === 'error') {
      var ec = document.getElementById('sp-error-card');
      var em = document.getElementById('sp-error-msg');
      if (ec) ec.className = 'sp-error-card is-visible';
      if (em) em.textContent = d.error || 'Unknown error.';
    }
    if (d.stage !== 'done' && d.stage !== 'error') { setTimeout(poll, 2000); }
  }
  function poll() {
    fetch(url).then(function(r){ return r.json(); }).then(update).catch(function(){ setTimeout(poll, 3000); });
  }
  poll();
})();
`;

/** The 4 pipeline steps shown on the progress page (excluding queued). */
const PIPELINE_STEPS: Array<{ stage: SpecStage; label: string; icon: string }> = [
  { stage: "analyzing", label: "Analyzing spec", icon: "🔍" },
  { stage: "writing", label: "Writing code", icon: "✍️" },
  { stage: "opening_pr", label: "Opening PR", icon: "📬" },
  { stage: "done", label: "Done", icon: "✅" },
];

function ProgressPage({
  owner,
  repo,
  job,
}: {
  owner: string;
  repo: string;
  jobId: string;
  job: SpecJob;
}) {
  const stageIdx = (s: SpecStage) => {
    const order: SpecStage[] = ["queued", "analyzing", "writing", "opening_pr", "done", "error"];
    return order.indexOf(s);
  };
  const curIdx = stageIdx(job.stage);

  return (
    <div class="sp-wrap">
      <header class="sp-head">
        <div class="sp-eyebrow">Spec to PR · Live progress</div>
        <h1 class="sp-title">Building your PR…</h1>
        <p class="sp-sub">Sit tight — Claude is generating the implementation.</p>
      </header>

      <ul class="sp-timeline">
        {PIPELINE_STEPS.map(({ stage, label, icon }) => {
          const sIdx = stageIdx(stage);
          const isDone = curIdx > sIdx || (job.stage === "done" && stage === "done");
          const isActive = job.stage === stage;
          const isError = job.stage === "error" && stage === "writing"; // show error on writing step
          let dotClass = "sp-dot";
          let lblClass = "sp-step-label";
          if (isDone) { dotClass += " is-done"; lblClass += " is-done"; }
          else if (isActive) { dotClass += " is-active"; lblClass += " is-active"; }
          else if (isError) { dotClass += " is-error"; lblClass += " is-error"; }

          return (
            <li class="sp-step">
              <div id={`dot-${stage}`} class={dotClass}>{icon}</div>
              <div class="sp-step-body">
                <div id={`lbl-${stage}`} class={lblClass}>{label}</div>
              </div>
            </li>
          );
        })}
        {/* always show the error stage dot so JS can target it */}
        <li class="sp-step" id="step-error" style={job.stage === "error" ? "" : "display:none"}>
          <div id="dot-error" class={`sp-dot${job.stage === "error" ? " is-error" : ""}`}>❌</div>
          <div class="sp-step-body">
            <div id="lbl-error" class={`sp-step-label${job.stage === "error" ? " is-error" : ""}`}>Error</div>
          </div>
        </li>
      </ul>

      {/* Done card — hidden until JS reveals it */}
      <div
        id="sp-done-card"
        class={`sp-done-card${job.stage === "done" ? " is-visible" : ""}`}
      >
        <h2>PR opened!</h2>
        {job.completedAt && job.startedAt && (
          <p>
            Merged in {Math.round((job.completedAt - job.startedAt) / 1000)}s
          </p>
        )}
        <a
          id="sp-pr-link"
          class="sp-done-link"
          href={job.prNumber ? `/${owner}/${repo}/pulls/${job.prNumber}` : "#"}
          data-base={`/${owner}/${repo}/pulls`}
        >
          View PR {job.prNumber ? `#${job.prNumber}` : ""}
        </a>
      </div>

      {/* Error card */}
      <div
        id="sp-error-card"
        class={`sp-error-card${job.stage === "error" ? " is-visible" : ""}`}
      >
        <p id="sp-error-msg">{job.error || ""}</p>
        <a href={`/${owner}/${repo}/spec`}>Try again</a>
      </div>

      <script dangerouslySetInnerHTML={{ __html: PROGRESS_POLL_JS }} />
      <style dangerouslySetInnerHTML={{ __html: progressStyles }} />
    </div>
  );
}

// GET /:owner/:repo/spec/:jobId/progress — HTML progress page
specs.get("/:owner/:repo/spec/:jobId/progress", softAuth, requireAuth, async (c) => {
  const { owner, repo, jobId } = c.req.param();
  const user = c.get("user")!;

  const resolved = await resolveRepo(owner, repo);
  if (!resolved) return c.notFound();
  if (!hasWriteAccess(resolved, user.id)) return c.text("Forbidden", 403);

  const job = specJobs.get(jobId);
  if (!job) {
    // Job expired or unknown — redirect to spec form.
    return c.redirect(`/${owner}/${repo}/spec`);
  }

  // If already done, redirect straight to the PR.
  if (job.stage === "done" && job.prNumber) {
    return c.redirect(`/${owner}/${repo}/pulls/${job.prNumber}`);
  }

  return c.html(
    <Layout title={`Generating PR — ${owner}/${repo}`} user={user}>
      <RepoHeader owner={owner} repo={repo} />
      <ProgressPage owner={owner} repo={repo} jobId={jobId} job={job} />
    </Layout>
  );
});

// GET /:owner/:repo/spec/:jobId/progress/events — SSE stream
specs.get("/:owner/:repo/spec/:jobId/progress/events", softAuth, requireAuth, async (c) => {
  const { owner, repo, jobId } = c.req.param();
  const user = c.get("user")!;

  const resolved = await resolveRepo(owner, repo);
  if (!resolved) return c.json({ error: "Not found" }, 404);
  if (!hasWriteAccess(resolved, user.id)) return c.json({ error: "Forbidden" }, 403);

  const job = specJobs.get(jobId);
  if (!job) return c.json({ error: "Job not found" }, 404);

  const topic = specJobTopic(jobId);
  const encoder = new TextEncoder();

  const stream = new ReadableStream<Uint8Array>({
    start(controller) {
      let closed = false;
      const safeEnqueue = (chunk: string) => {
        if (closed) return;
        try { controller.enqueue(encoder.encode(chunk)); } catch { closed = true; }
      };

      safeEnqueue(": open\n\n");

      // Send current state immediately so late connectors get a snapshot.
      const snapJob = specJobs.get(jobId);
      if (snapJob) {
        const payload = JSON.stringify({ stage: snapJob.stage, label: snapJob.label, prNumber: snapJob.prNumber, error: snapJob.error });
        safeEnqueue(`event: stage\ndata: ${payload}\n\n`);
      }

      const unsubscribe = subscribe(topic, (ev) => {
        let out = "";
        if (ev.event) out += `event: ${ev.event}\n`;
        const data = typeof ev.data === "string" ? ev.data : JSON.stringify(ev.data);
        for (const line of data.split("\n")) out += `data: ${line}\n`;
        out += "\n";
        safeEnqueue(out);
      });

      const ping = setInterval(() => safeEnqueue(": ping\n\n"), 25_000);

      const cleanup = () => {
        if (closed) return;
        closed = true;
        clearInterval(ping);
        unsubscribe();
        try { controller.close(); } catch { /* already closed */ }
      };

      const signal = c.req.raw.signal;
      if (signal) {
        if (signal.aborted) cleanup();
        else signal.addEventListener("abort", cleanup, { once: true });
      }
    },
  });

  return new Response(stream, {
    status: 200,
    headers: {
      "Content-Type": "text/event-stream; charset=utf-8",
      "Cache-Control": "no-cache, no-transform",
      "Connection": "keep-alive",
      "X-Accel-Buffering": "no",
    },
  });
});

// GET /:owner/:repo/spec/:jobId/status — JSON polling endpoint
specs.get("/:owner/:repo/spec/:jobId/status", softAuth, requireAuth, async (c) => {
  const { owner, repo, jobId } = c.req.param();
  const user = c.get("user")!;

  const resolved = await resolveRepo(owner, repo);
  if (!resolved) return c.json({ error: "Not found" }, 404);
  if (!hasWriteAccess(resolved, user.id)) return c.json({ error: "Forbidden" }, 403);

  const job = specJobs.get(jobId);
  if (!job) return c.json({ error: "Job not found or expired" }, 404);

  return c.json({
    jobId: job.id,
    stage: job.stage,
    label: job.label,
    prNumber: job.prNumber,
    error: job.error,
    startedAt: job.startedAt,
    completedAt: job.completedAt,
  });
});

// ─── GET /specs — dashboard listing all specs across the user's repos ──────
//
// Walks every repo the signed-in user owns, looks at `.gluecron/specs/*.md`
// on the default branch, parses the front-matter for `status:` + `title:`,
// and surfaces a flat list with linked PR (when one exists). Soft-fails on
// any repo that can't be scanned — the dashboard still renders.

interface SpecRow {
  ownerName: string;
  repoName: string;
  specPath: string;
  title: string;
  status: SpecStatus;
  prNumber: number | null;
}

async function collectSpecsForOwner(ownerId: string): Promise<SpecRow[]> {
  let owner: { username: string } | undefined;
  try {
    const [row] = await db
      .select({ username: users.username })
      .from(users)
      .where(eq(users.id, ownerId))
      .limit(1);
    owner = row;
  } catch {
    return [];
  }
  if (!owner) return [];

  let repos: Array<{ id: string; name: string; defaultBranch: string }> = [];
  try {
    repos = await db
      .select({
        id: repositories.id,
        name: repositories.name,
        defaultBranch: repositories.defaultBranch,
      })
      .from(repositories)
      .where(
        and(eq(repositories.ownerId, ownerId), eq(repositories.isArchived, false))
      )
      .limit(100);
  } catch {
    return [];
  }

  const out: SpecRow[] = [];
  for (const repo of repos) {
    const branch = repo.defaultBranch || "main";
    let paths: string[] = [];
    try {
      const tree = await getTreeRecursive(owner.username, repo.name, branch, 5000);
      if (!tree) continue;
      paths = tree.tree
        .filter(
          (e) =>
            e.type === "blob" &&
            e.path.startsWith(".gluecron/specs/") &&
            e.path.toLowerCase().endsWith(".md")
        )
        .map((e) => e.path);
    } catch {
      continue;
    }
    for (const p of paths) {
      let content = "";
      try {
        const blob = await getBlob(owner.username, repo.name, branch, p);
        if (!blob || blob.isBinary) continue;
        content = blob.content;
      } catch {
        continue;
      }
      const parsed = parseFrontMatter(content);
      const title =
        (parsed.frontMatter.title && parsed.frontMatter.title.trim()) ||
        (p.split("/").pop() || p).replace(/\.md$/i, "");
      const statusRaw = (parsed.frontMatter.status || "draft").toLowerCase();
      const status: SpecStatus =
        statusRaw === "draft" ||
        statusRaw === "ready" ||
        statusRaw === "building" ||
        statusRaw === "shipped" ||
        statusRaw === "failed"
          ? (statusRaw as SpecStatus)
          : "draft";

      // Best-effort PR lookup: any PR whose body mentions the spec path
      // and carries the spec marker. Newest first.
      let prNumber: number | null = null;
      try {
        const [pr] = await db
          .select({ number: pullRequests.number })
          .from(pullRequests)
          .where(
            and(
              eq(pullRequests.repositoryId, repo.id),
              like(pullRequests.body, `%${AI_SPEC_PR_MARKER}%`),
              like(pullRequests.body, `%${p}%`)
            )
          )
          .orderBy(pullRequests.createdAt)
          .limit(1);
        if (pr) prNumber = pr.number;
      } catch {
        prNumber = null;
      }

      out.push({
        ownerName: owner.username,
        repoName: repo.name,
        specPath: p,
        title,
        status,
        prNumber,
      });
    }
  }
  return out;
}

specs.get("/specs", softAuth, requireAuth, async (c) => {
  const user = c.get("user")!;
  const rows = await collectSpecsForOwner(user.id);

  const byStatus = (s: SpecStatus) => rows.filter((r) => r.status === s);

  const statusBadgeColors: Record<SpecStatus, string> = {
    draft: "rgba(148,163,184,0.16)",
    ready: "rgba(54,197,214,0.18)",
    building: "rgba(140,109,255,0.20)",
    shipped: "rgba(34,197,94,0.18)",
    failed: "rgba(248,113,113,0.18)",
  };

  return c.html(
    <Layout title="Specs — Gluecron" user={user}>
      <div class="specs-wrap">
        <header class="specs-head">
          <div class="specs-eyebrow">
            <span class="specs-eyebrow-dot" aria-hidden="true" />
            Account · Specs dashboard
            <span class="specs-pill-experimental">Experimental</span>
          </div>
          <h1 class="specs-title">
            <span class="specs-title-grad">Your spec library.</span>
          </h1>
          <p class="specs-sub">
            Every <code>.gluecron/specs/*.md</code> file across your
            repositories. Set a spec's front-matter to{" "}
            <code>status: ready</code> and the autopilot picks it up within
            two minutes to open an implementation PR tagged{" "}
            <code>ai:spec-implementation</code>.
          </p>
        </header>

        <section class="specs-section">
          <header class="specs-section-head">
            <h2 class="specs-section-title">All specs ({rows.length})</h2>
            <p class="specs-section-sub">
              {byStatus("ready").length} ready · {byStatus("building").length}{" "}
              building · {byStatus("shipped").length} shipped ·{" "}
              {byStatus("failed").length} failed · {byStatus("draft").length}{" "}
              draft
            </p>
          </header>
          <div class="specs-section-body">
            {rows.length === 0 ? (
              <p class="specs-field-hint" style="font-size:13px;">
                No specs yet. Create a file like{" "}
                <code>.gluecron/specs/my-feature.md</code> in any of your
                repos with front-matter{" "}
                <code>---\ntitle: Add dark mode\nstatus: ready\n---</code> and
                it will land here.
              </p>
            ) : (
              <table style="width:100%;border-collapse:collapse;font-size:13px;">
                <thead>
                  <tr style="text-align:left;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:0.06em;">
                    <th style="padding:8px 4px;">Repo</th>
                    <th style="padding:8px 4px;">Title</th>
                    <th style="padding:8px 4px;">Status</th>
                    <th style="padding:8px 4px;">PR</th>
                    <th style="padding:8px 4px;">Path</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((r) => (
                    <tr style="border-top:1px solid var(--border);">
                      <td style="padding:10px 4px;">
                        <a href={`/${r.ownerName}/${r.repoName}`}>
                          {r.ownerName}/{r.repoName}
                        </a>
                      </td>
                      <td style="padding:10px 4px;color:var(--text-strong);">
                        {r.title}
                      </td>
                      <td style="padding:10px 4px;">
                        <span
                          style={`display:inline-block;padding:2px 8px;border-radius:9999px;font-family:var(--font-mono);font-size:11px;background:${statusBadgeColors[r.status]};color:var(--text);`}
                        >
                          {r.status}
                        </span>
                      </td>
                      <td style="padding:10px 4px;">
                        {r.prNumber ? (
                          <a
                            href={`/${r.ownerName}/${r.repoName}/pulls/${r.prNumber}`}
                          >
                            #{r.prNumber}
                          </a>
                        ) : (
                          <span style="color:var(--text-muted);">—</span>
                        )}
                      </td>
                      <td style="padding:10px 4px;font-family:var(--font-mono);font-size:11.5px;color:var(--text-muted);">
                        <a
                          href={`/${r.ownerName}/${r.repoName}/blob/main/${r.specPath}`}
                        >
                          {r.specPath}
                        </a>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </section>

        <style dangerouslySetInnerHTML={{ __html: specsStyles }} />
      </div>
    </Layout>
  );
});

export default specs;
